  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// User profile linked to Telegram\nmodel User {\n  id            Int       @id @default(autoincrement())\n  telegramId    String    @unique\n  username      String?\n  firstName     String?\n  lastName      String?\n  photoUrl      String?\n  languageCode  String?   @default(\"en\")\n  xp            Int       @default(0)\n  level         Int       @default(1)\n  streak        Int       @default(0)\n  lastSessionAt DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  // Relations\n  teamMemberships TeamMember[]\n  sessions        FocusSession[]\n  userProgress    UserProgress[]\n  teamProgress    TeamProgress[]\n\n  @@index([telegramId])\n}\n\n// Team/Guild\nmodel Team {\n  id             Int      @id @default(autoincrement())\n  name           String\n  description    String?\n  inviteCode     String   @unique\n  maxMembers     Int      @default(10)\n  weeklyGoal     Int      @default(100) // minutes\n  weeklyProgress Int      @default(0)\n  weekStart      DateTime @default(now())\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  // Relations\n  members  TeamMember[]\n  progress TeamProgress[]\n\n  @@index([inviteCode])\n}\n\n// Team membership\nmodel TeamMember {\n  id       Int      @id @default(autoincrement())\n  userId   Int\n  teamId   Int\n  role     String   @default(\"member\") // owner, admin, member\n  joinedAt DateTime @default(now())\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  team Team @relation(fields: [teamId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, teamId])\n  @@index([teamId])\n}\n\n// Focus session - server tracked\nmodel FocusSession {\n  id             Int      @id @default(autoincrement())\n  userId         Int\n  plannedMinutes Int\n  actualMinutes  Int\n  status         String   @default(\"completed\") // completed, interrupted, failed\n  startedAt      DateTime\n  completedAt    DateTime\n  xpEarned       Int      @default(0)\n  isValid        Boolean  @default(true) // anti-cheat flag\n  createdAt      DateTime @default(now())\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([startedAt])\n}\n\n// Weekly team progress tracking\nmodel TeamProgress {\n  id                 Int      @id @default(autoincrement())\n  teamId             Int\n  userId             Int\n  weekStart          DateTime\n  minutesContributed Int      @default(0)\n  createdAt          DateTime @default(now())\n  updatedAt          DateTime @updatedAt\n\n  // Relations\n  team Team @relation(fields: [teamId], references: [id], onDelete: Cascade)\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([teamId, userId, weekStart])\n  @@index([teamId, weekStart])\n}\n\n// Individual user progress tracking\nmodel UserProgress {\n  id                Int      @id @default(autoincrement())\n  userId            Int\n  date              DateTime @db.Date\n  minutesFocused    Int      @default(0)\n  sessionsCompleted Int      @default(0)\n  xpEarned          Int      @default(0)\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, date])\n  @@index([userId, date])\n}\n",
